#define ELEMENTS_PER_THREAD (8)
#define FUSION_DEGREE (4)
#define BLOCK_SIZE (256)

template<class T>
inline T conv_int(const int i){ return static_cast<T>(i); }

template<class T>
inline T mad(const T a, const T b, const T c){ return a*b+c; }

template<class T>
inline bool equal(const T a, const T b){ return a==b; }

template <class T, unsigned int granularity, unsigned int fusion_degree, unsigned int compute_iterations, bool TemperateUnroll>
void benchmark_func_cpu(T seed, T *data, size_t total_elements, int num_threads){
	const int stride = BLOCK_SIZE;
	const size_t total_work = total_elements / sizeof(T);
	const size_t per_thread = total_work / num_threads;

	#pragma omp parallel for
	for(int t=0; t<num_threads; t++){
		size_t idx = t * per_thread;
		size_t thread_end = (t == num_threads-1) ? total_work : (t+1) * per_thread;

		T tmps[granularity];
		for(size_t k=0; k<fusion_degree; k++){
			for(size_t j=0; j<granularity; j++){
				size_t access_idx = idx + j*stride + k*total_work;
				if(access_idx < total_work){
					tmps[j] = data[access_idx];

					for(unsigned int i=0; i<compute_iterations; i++){
						tmps[j] = mad(tmps[j], tmps[j], seed);
					}
				}
			}

			T sum = conv_int<T>(0);
			for(size_t j=0; j<granularity; j+=2){
				if(j+1 < granularity){
					sum = mad(tmps[j], tmps[j+1], sum);
				}
			}

			if(equal(sum, conv_int<T>(-1))){
				size_t store_idx = idx + k*total_work;
				if(store_idx < total_work){
					data[store_idx] = sum;
				}
			}
		}
	}
}

double get_time_ms(){
	auto now = std::chrono::high_resolution_clock::now();
	auto ms = std::chrono::duration<double, std::milli>(now.time_since_epoch()).count();
	return ms;
}

