void runbench_cpu(double *cd, size_t size, bool doHalfs){
	const size_t compute_grid_size = size/ELEMENTS_PER_THREAD/FUSION_DEGREE;
	const int TOTAL_BLOCKS = compute_grid_size/BLOCK_SIZE;
	const long long computations = (ELEMENTS_PER_THREAD*(long long)compute_grid_size+(2*ELEMENTS_PER_THREAD*compute_iterations)*(long long)compute_grid_size)*FUSION_DEGREE;
	const long long memoryoperations = size;
	const int num_threads = omp_get_max_threads();

	double start_time, end_time;
	double kernel_time_mad_sp, kernel_time_mad_dp, kernel_time_mad_hp, kernel_time_mad_int;

	start_time = omp_get_wtime();
	benchmark_func_cpu< float, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations, false >(1.0f, (float*)cd, size, num_threads);
	end_time = omp_get_wtime();
	kernel_time_mad_sp = (end_time - start_time) * 1000.0;

	start_time = omp_get_wtime();
	benchmark_func_cpu< double, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations, false >(1.0, cd, size, num_threads);
	end_time = omp_get_wtime();
	kernel_time_mad_dp = (end_time - start_time) * 1000.0;

	kernel_time_mad_hp = 0.0;
